DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "parserVectorUtils.pl",
  "contextForm.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$actual_solution = Real(non_zero_random(-9,9));
$m = random(2,9);
$b = non_zero_random(-9,9);
$left = Formula("$m x + $b")->reduce;
$right = Formula($left->eval(x => $actual_solution))->reduce;
$proposed_solution = random(0,2) ? $actual_solution : $actual_solution + non_zero_random(-3,3);
Context("LimitedNumeric");
$lefteval = Real($left->eval(x => $proposed_solution));
$righteval = Real($right->eval(x => $proposed_solution));
$inequality = list_random('\lt', '\gt', '\leq', '\geq', '\neq');
$truefalse = (
  ($inequality eq '\lt') ?
  ($lefteval < $righteval) :
  (
    ($inequality eq '\gt') ?
    ($lefteval > $righteval) :
    (
      ($inequality eq '\leq') ?
      ($lefteval <= $righteval) :
      (
        ($inequality eq '\geq') ?
        ($lefteval >= $righteval) :
        ($lefteval != $righteval)
      )
    )
  )
);
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], $truefalse ? 0 : 1, showInStatic => 0);
if ($inequality eq '\lt' && $lefteval < $righteval) {
  $sol[0] = "is less than";
  $sol[1] = "is a solution to";
} elsif ($inequality eq '\lt') {
  $sol[0] = "is not less than";
  $sol[1] = "is not a solution to";
} elsif ($inequality eq '\gt' && $lefteval > $righteval) {
  $sol[0] = "is greater than";
  $sol[1] = "is a solution to";
} elsif ($inequality eq '\gt') {
  $sol[0] = "is not greater than";
  $sol[1] = "is not a solution to";
} elsif ($inequality eq '\leq' && $lefteval <= $righteval) {
  $sol[0] = "is less than or equal to";
  $sol[1] = "is a solution to";
} elsif ($inequality eq '\leq') {
  $sol[0] = "is not less than or equal to";
  $sol[1] = "is not a solution to";
} elsif ($inequality eq '\geq' && $lefteval >= $righteval) {
  $sol[0] = "is greater than or equal to";
  $sol[1] = "is a solution to";
} else {
  $sol[0] = "is not greater than or equal to";
  $sol[1] = "is not a solution to";
}

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given number is a solution to the given inequality.

Is [`[$proposed_solution]`] a solution to [`[$left][$inequality][$right]\text{?}`]

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`[$inequality]`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{[$inequality]}`]'),
     PGML('[`[$righteval->TeX]`]'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
We have to substitute [`[$proposed_solution]`] in for [`x`] and simplify each side. The left side simplifies to [`[$lefteval]`] and the right side simplifies to [`[$righteval]\text{.}`] Since [`[$lefteval]`] [$sol[0]] [`[$righteval]\text{,}`] [`[$proposed_solution]`] [$sol[1]] [`[$left]=[$right]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
